import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { BrowserRouter, Routes, Route, Link, useNavigate, useParams, Outlet, useLocation } from 'react-router-dom';
import { LogIn, UserPlus, Building, PlusCircle, Home, MapPin, Search, Edit, Trash2, MessageSquare, Heart, LayoutDashboard, Bell, ArrowLeft, Bed, Bath, Send, Star, User, ShieldCheck, UploadCloud, AlertTriangle, SlidersHorizontal, Sparkles } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, RadialBarChart, RadialBar } from 'recharts';
import toast, { Toaster } from 'react-hot-toast';
import axios from 'axios';

// --- API & WEBSOCKET CONFIGURATION ---
const API_URL = 'http://localhost:3001';
export const WEBSOCKET_URL = API_URL.replace(/^http/, 'ws');
const api = axios.create({ baseURL: API_URL });

api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) config.headers['Authorization'] = `Bearer ${token}`;
    return config;
  },
  (error) => Promise.reject(error)
);

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response && (error.response.status === 401 || error.response.status === 403)) {
      localStorage.removeItem('currentUser');
      localStorage.removeItem('token');
      if (window.location.pathname !== '/login') {
        toast.error("Your session has expired. Please log in again.");
        window.location.href = '/login';
      }
    }
    return Promise.reject(error);
  }
);

// --- CONTEXTS ---
const AuthContext = createContext();
const SearchContext = createContext();
const NotificationContext = createContext();
const WebSocketContext = createContext(null);
const FilterContext = createContext();

// --- PROVIDERS ---
export const AuthProvider = ({ children }) => {
    const [currentUser, setCurrentUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        try {
            const storedUser = localStorage.getItem("currentUser");
            if (storedUser) setCurrentUser(JSON.parse(storedUser));
        } catch (error) {
            console.error("Failed to parse stored user", error);
            localStorage.clear();
        }
        setLoading(false);
    }, []);

    useEffect(() => {
        if (currentUser) {
            localStorage.setItem("currentUser", JSON.stringify(currentUser));
        } else {
            localStorage.removeItem("currentUser");
            localStorage.removeItem("token");
        }
    }, [currentUser]);

    const logout = useCallback(() => setCurrentUser(null), []);

    return (
        <AuthContext.Provider value={{ currentUser, setCurrentUser, logout, loading }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const SearchProvider = ({ children }) => {
    const [searchTerm, setSearchTerm] = useState('');
    return (
        <SearchContext.Provider value={{ searchTerm, setSearchTerm }}>
            {children}
        </SearchContext.Provider>
    );
};

export const WebSocketProvider = ({ children }) => {
    const { currentUser } = useContext(AuthContext);
    const ws = useRef(null);
    const [lastMessage, setLastMessage] = useState(null);

    useEffect(() => {
        if (currentUser && !ws.current) {
            ws.current = new WebSocket(WEBSOCKET_URL);
            ws.current.onopen = () => {
                const token = localStorage.getItem("token");
                ws.current.send(JSON.stringify({ type: 'auth', token }));
            };
            ws.current.onmessage = (event) => {
                setLastMessage(event.data);
            };
            ws.current.onclose = () => {
                ws.current = null;
            };
            return () => {
                if (ws.current) {
                    ws.current.close();
                    ws.current = null;
                }
            };
        } else if (!currentUser && ws.current) {
            ws.current.close();
            ws.current = null;
        }
    }, [currentUser]);

    const sendMessage = useCallback((message) => {
        if (ws.current && ws.current.readyState === WebSocket.OPEN) {
            ws.current.send(message);
        }
    }, []);

    return (
        <WebSocketContext.Provider value={{ lastMessage, sendMessage }}>
            {children}
        </WebSocketContext.Provider>
    );
};

export const NotificationProvider = ({ children }) => {
    const { currentUser } = useContext(AuthContext);
    const { lastMessage } = useContext(WebSocketContext);
    const [notifications, setNotifications] = useState([]);
    const [unreadCount, setUnreadCount] = useState(0);

    useEffect(() => {
        if (currentUser) {
            const fetchNotifications = async () => {
                try {
                    const { data } = await api.get('/api/notifications');
                    setNotifications(data);
                    setUnreadCount(data.filter(n => !n.isRead).length);
                } catch (error) {
                    console.error("Failed to fetch notifications");
                }
            };
            fetchNotifications();
        }
    }, [currentUser]);

    useEffect(() => {
        if (lastMessage) {
            const data = JSON.parse(lastMessage);
            if (data.type === 'newNotification') {
                toast.success('You have a new notification!');
                setNotifications(prev => [data.payload, ...prev]);
                setUnreadCount(prev => prev + 1);
            } else if (data.type === 'newMessage' && !window.location.pathname.includes('/messages/')) {
                toast.success('You have a new message!');
            }
        }
    }, [lastMessage]);

    const markAllAsRead = async () => {
        try {
            await api.put('/api/notifications/mark-read');
            setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
            setUnreadCount(0);
        } catch (error) {
            toast.error("Could not mark notifications as read.");
        }
    };

    return (
        <NotificationContext.Provider value={{ notifications, unreadCount, markAllAsRead }}>
            {children}
        </NotificationContext.Provider>
    );
};

export const FilterProvider = ({ children }) => {
    const [filters, setFilters] = useState({
        city: 'All',
        minPrice: '0',
        maxPrice: '100000',
        bedrooms: 'Any',
        propertyType: 'All',
    });

    const resetFilters = () => {
        setFilters({
            city: 'All',
            minPrice: '0',
            maxPrice: '100000',
            bedrooms: 'Any',
            propertyType: 'All',
        });
    };

    return (
        <FilterContext.Provider value={{ filters, setFilters, resetFilters }}>
            {children}
        </FilterContext.Provider>
    );
};


