                            <li key={item.label}>
                                <Link to={item.path} className={`flex items-center gap-3 px-4 py-3 my-2 rounded-lg transition-colors ${isActive ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
