                    )}
                </div>
                {useAuth().currentUser?.userType === 'landlord' && (
                    <Link to="/add-property" className="bg-indigo-600 text-white font-bold py-2 px-4 rounded-lg flex items-center gap-2">
                        <PlusCircle size={20} /><span>New Property</span>
