            {/* NEW: Reviews Section */}
            <div className="bg-slate-800/50 p-8 rounded-2xl border border-slate-700 max-w-6xl mx-auto">
                <h2 className="text-2xl font-bold text-white mb-6">Reviews ({reviews.length})</h2>
                
